// Google Places — last-layer fallback, called ONLY when the user opens a detail
// page and taps「查 Google 補充」. The server holds the key + enforces the $5/day cap.
//
// ToS shape on the client:
//  • Raw Google content (phone / hours / summary) is shown live and NEVER written
//    to storage — it lives only in the DOM until the user leaves.
//  • Only place_id + our derived facts are persisted (dm.placeFacts), as the
//    layer-③「own signal」so we can hint without re-calling.

const RECALL = (import.meta.env.VITE_RECALL_ENDPOINT as string | undefined) || "";
const ENDPOINT =
  (import.meta.env.VITE_PLACES_ENDPOINT as string | undefined) ||
  (RECALL ? RECALL.replace(/\/recall$/, "/places") : "");

export interface PlacesDisplay {
  phone: string | null;
  hours: string[] | null;
  openNow: boolean | null;
  priceLevel: string | null;
  priceRange: string | null;
  rating: number | null;
  userRatingCount: number | null;
  summary: string | null;
  summaryDisclosure: string | null;
  googleMapsUri: string | null;
  attribution: string;
}
export interface PlaceFacts {
  placeId: string;
  hasPhone: boolean;
  hasHours: boolean;
  hasSummary: boolean;
  priceLevel: string | null;
}
export interface PlacesResult {
  ok: boolean;
  matched?: boolean;
  reason?: string;
  display?: PlacesDisplay;
  facts?: PlaceFacts;
}

export function placesEnabled(): boolean {
  return !!ENDPOINT;
}

export async function fetchPlaces(name: string, addr?: string): Promise<PlacesResult | null> {
  if (!ENDPOINT) return null;
  try {
    const res = await fetch(ENDPOINT, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ name, addr }),
      signal: AbortSignal.timeout(15000), // Render cold start → fall back to FEHD
    });
    if (!res.ok) return null;
    return (await res.json()) as PlacesResult;
  } catch {
    return null;
  }
}

// ---- derived-facts store (ToS-safe: place_id + our own booleans/bucket) -------
const FKEY = "dm.placeFacts";
function readAll(): Record<string, PlaceFacts> {
  try {
    return JSON.parse(localStorage.getItem(FKEY) || "{}");
  } catch {
    return {};
  }
}
export function getPlaceFacts(restaurantId: string): PlaceFacts | null {
  return readAll()[restaurantId] ?? null;
}
export function savePlaceFacts(restaurantId: string, facts: PlaceFacts): void {
  try {
    const all = readAll();
    all[restaurantId] = facts;
    localStorage.setItem(FKEY, JSON.stringify(all));
  } catch {
    /* storage full — non-fatal */
  }
}
